import base64, json
from pathlib import Path

files = {"backend/abc_parser.py": "", "backend/database.py": "", "backend/import_tunes.py": "", "backend/main.py": "", "frontend/index.html": "", "frontend/static/style.css": "", "frontend/static/app.js": ""}

print("Creating project files...")
for path, data in files.items():
    p = Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(data))
    print(f"  created {path}")

Path("data").mkdir(exist_ok=True)
print()
print("Done! Now run:")
print('  python3 backend/import_tunes.py "/path/to/your/file.abc"')
